sql:
SELECT MAX(total_points) AS max_total_score
FROM (
  SELECT skater_id, SUM(total_points) AS total_points
  FROM results
  GROUP BY skater_id
) AS skater_total_scores;

external_knowledge:
- "Total points" represent the cumulative score achieved by the skater in the competition;
- "Average performance score" is the mean score of the skater's performances in the competition;
- "Top skater" refers to the skater with the highest total points in each competition.
